1	import { expect, test as base, vi } from "vitest";
2	import { render } from "vitest-browser-react";
3	import type { UpdateProfileResult } from "./profile-edit.action";
4	import { ProfileEditPresenter } from "./profile-edit.presenter.form.client";
5	
6	const editProfileMock =
7	  vi.fn<(nickname: string, introduce: string) => Promise<UpdateProfileResult>>();
8	
9	vi.mock("./profile-edit.action", () => ({
10	  editProfile: (nickname: string, introduce: string) =>
11	    editProfileMock(nickname, introduce),
12	}));
13	
14	const test = base.extend({
15	  editProfile: [
16	    async ({}, provide: (v: typeof editProfileMock) => Promise<void>) => {
17	      editProfileMock.mockReset();
18	      await provide(editProfileMock);
19	    },
20	    { auto: true },
21	  ],
22	});
23	
24	test("初期値が入力欄に表示される", async () => {
25	  const screen = await render(
26	    <ProfileEditPresenter defaultNickname="taro" defaultIntroduce="hello" />,
27	  );
28	
29	  await expect.element(screen.getByLabelText(/ニックネーム/)).toHaveValue("taro");
30	  await expect.element(screen.getByLabelText(/自己紹介/)).toHaveValue("hello");
31	});
32	
33	test("空のニックネームで blur すると必須エラーが表示される", async () => {
34	  const screen = await render(<ProfileEditPresenter defaultNickname="taro" />);
35	
36	  const nickname = screen.getByLabelText(/ニックネーム/);
37	  await nickname.clear();
38	  await screen.getByLabelText(/自己紹介/).click();
39	
40	  await expect
41	    .element(screen.getByText("ニックネームは必須です"))
42	    .toBeInTheDocument();
43	});
44	
45	test("ニックネーム 50 文字（上限）は受理される", async () => {
46	  const screen = await render(<ProfileEditPresenter defaultNickname="taro" />);
47	
48	  const nickname = screen.getByLabelText(/ニックネーム/);
49	  await nickname.fill("a".repeat(50));
50	  await screen.getByLabelText(/自己紹介/).click();
51	
52	  await expect
53	    .element(screen.getByText("ニックネームは50文字以内で入力してください"))
54	    .not.toBeInTheDocument();
55	});
56	
57	test("ニックネーム 51 文字で blur すると文字数超過エラーが表示される", async () => {
58	  const screen = await render(<ProfileEditPresenter defaultNickname="taro" />);
59	
60	  const nickname = screen.getByLabelText(/ニックネーム/);
61	  await nickname.fill("a".repeat(51));
62	  await screen.getByLabelText(/自己紹介/).click();
