import { createClient } from "@/lib/supabase/server";

export interface Profile {
  nickname: string;
  introduce: string;
}

export type GetProfileErrorCode =
  | "UNAUTHORIZED"
  | "NOT_FOUND"
  | "INTERNAL_ERROR";

export type GetProfileResult =
  | { success: true; profile: Profile }
  | { success: false; code: GetProfileErrorCode };

export async function getProfile(): Promise<GetProfileResult> {
  const supabase = await createClient();
  const {
    data: { session },
  } = await supabase.auth.getSession();

  if (!session) return { success: false, code: "UNAUTHORIZED" };

  const res = await fetch(
    `${process.env.API_URL}/v1/users/${session.user.id}`,
    { headers: { Authorization: `Bearer ${session.access_token}` } },
  );

  if (res.status === 404) return { success: false, code: "NOT_FOUND" };
  if (!res.ok) return { success: false, code: "INTERNAL_ERROR" };

  const profile = (await res.json()) as Profile;
  return { success: true, profile };
}

import { createClient } from '@/lib/supabase/server'
import { NextResponse } from 'next/server'

export async function GET(request: Request): Promise<NextResponse> {
  const { searchParams, origin } = new URL(request.url)
  const code = searchParams.get('code')
  let next = searchParams.get('next') ?? '/'
  if (!next.startsWith('/')) {
    next = '/'
  }

  if (code) {
    const supabase = await createClient()
    const { error } = await supabase.auth.exchangeCodeForSession(code)
    if (!error) {
      const forwardedHost = request.headers.get('x-forwarded-host')
      const isLocalEnv = process.env.NODE_ENV === 'development'
      if (isLocalEnv) {
        return NextResponse.redirect(`${origin}${next}`)
      } else if (forwardedHost) {
        return NextResponse.redirect(`https://${forwardedHost}${next}`)
      } else {
        return NextResponse.redirect(`${origin}${next}`)
      }
    }
  }

  return new NextResponse('認証に失敗しました。最初からお試しください。', { status: 400 })
}

import { expect, test as base, vi } from "vitest";
import type { getProfile as GetProfileFn } from "./profile.data";

const getSessionMock = vi.fn<() => Promise<{ data: { session: unknown } }>>();

vi.mock("@/lib/supabase/server", () => ({
  createClient: async () => ({
    auth: { getSession: getSessionMock },
  }),
}));

const test = base.extend<{ getProfile: typeof GetProfileFn }>({
  getProfile: async ({}, provide) => {
    getSessionMock.mockReset();
    vi.unstubAllGlobals();
    vi.unstubAllEnvs();
    vi.stubEnv("API_URL", "https://api.test.example");
    const { getProfile } = await import("./profile.data");
    await provide(getProfile);
  },
});

test("session が無い場合は UNAUTHORIZED コードを返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({ data: { session: null } });

  const result = await getProfile();

  expect(result).toEqual({ success: false, code: "UNAUTHORIZED" });
});

test("API が 404 を返した場合は NOT_FOUND コードを返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({
    data: {
      session: { user: { id: "user-1" }, access_token: "token-1" },
    },
  });
  vi.stubGlobal(
    "fetch",
    vi.fn(async () => new Response(null, { status: 404 })),
  );

  const result = await getProfile();

  expect(result).toEqual({ success: false, code: "NOT_FOUND" });
});

test("API が 500 を返した場合は INTERNAL_ERROR コードを返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({
    data: {
      session: { user: { id: "user-1" }, access_token: "token-1" },
    },
  });
  vi.stubGlobal(
    "fetch",
    vi.fn(async () => new Response(null, { status: 500 })),
  );

  const result = await getProfile();

  expect(result).toEqual({ success: false, code: "INTERNAL_ERROR" });
});

test("API が 200 を返した場合は Profile を返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({
    data: {
      session: { user: { id: "user-1" }, access_token: "token-1" },
    },
  });
  const fetchMock = vi.fn(
    async () =>
      Response.json({ nickname: "taro", introduce: "hi" }, {
        status: 200,
        headers: { "Content-Type": "application/json" },
      }),
  );
  vi.stubGlobal("fetch", fetchMock);

  const result = await getProfile();

  expect(result).toEqual({
    success: true,
    profile: { nickname: "taro", introduce: "hi" },
  });
  expect(fetchMock).toHaveBeenCalledWith(
    "https://api.test.example/v1/users/user-1",
    { headers: { Authorization: "Bearer token-1" } },
  );
});

